function getStarDistribution(distribution: { rating: number; count: number }[]): number[] {
  const result = [0, 0, 0, 0, 0];
  for (const item of distribution) {
    const index = item.rating - 1;
    if (index >= 0 && index < 5) result[index] = item.count;
  }
  return result;
}
